const driveItems = $('1. Buscar PDFs en Drive').all();
const sheetsData = $input.first().json;
const rows = sheetsData.values || [];
const headers = rows[0] || [];
const fileNameIdx = headers.indexOf('_fileName');

const existingFileNames = new Set();
if (fileNameIdx >= 0) {
  for (let i = 1; i < rows.length; i++) {
    const val = (rows[i][fileNameIdx] || '').trim();
    if (val) existingFileNames.add(val);
  }
}

const newPdfs = driveItems.filter(item => {
  const fileName = (item.json.name || '').trim();
  return fileName && !existingFileNames.has(fileName);
});

if (newPdfs.length === 0) {
  return [{ json: { status: 'No hay PDFs nuevos', totalNew: 0, totalDrive: driveItems.length, totalSheets: rows.length - 1 } }];
}

return newPdfs.map(pdf => ({
  json: {
    fileId: pdf.json.id,
    fileName: pdf.json.name,
    webViewLink: pdf.json.webViewLink || '',
    isNew: true,
    totalNew: newPdfs.length,
    totalDrive: driveItems.length,
    totalSheets: rows.length - 1
  }
}));

const items = $input.all();
const metaItems = $('4. Hay Nuevos?').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const meta = metaItems[i]?.json || {};

  const content = item.json?.output?.[0]?.content?.[0]?.text || '{}';
  let parsed;
  try {
    const clean = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    parsed = JSON.parse(clean);
  } catch (e) {
    parsed = {};
  }

  const now = new Date();
  const months = ['ENERO','FEBRERO','MARZO','ABRIL','MAYO','JUNIO','JULIO','AGOSTO','SEPTIEMBRE','OCTUBRE','NOVIEMBRE','DICIEMBRE'];
  const mes = months[now.getMonth()];
  const fecha = now.toISOString().split('T')[0];

  results.push({
    json: {
      appendBody: {
        values: [[
          mes,
          parsed.nombre || '',
          '',
          '',
          parsed.residencia || '',
          fecha,
          '',
          parsed.correo || '',
          parsed.telefono || '',
          'Google Drive (auto)',
          '',
          '',
          '',
          '',
          '',
          '',
          parsed.comentarios || '',
          'Nuevo',
          parsed.posicion || '',
          '',
          '',
          '',
          'insert',
          meta.fileId || '',
          meta.fileName || '',
          new Date().toISOString()
        ]]
      },
      fileName: meta.fileName || '',
      nombre: parsed.nombre || '',
      status: 'inserted'
    }
  });
}

return results;
